  WITH CHECK (((verified = false) AND ((created_by = (select auth.uid())) OR (EXISTS ( SELECT 1
   FROM profiles p
  WHERE ((p.id = (select auth.uid())) AND (p.email = companies.primary_hr_email)))))));

